  `score_mode`,
  `score_target`,
  `score_value`,
  `dimension`,
  `tag`,
  `sentiment`,
  `ai_summary_text`,
  `description`,
  `is_high_frequency`,
  `display_enabled`,
  `admin_enabled`,
  `status`,
  `created_by`,
  `updated_by`,
  `created_at`,
  `updated_at`
)
